'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { 
  MessageCircle, Phone, Mail, 
  ArrowUpRight 
} from 'lucide-react';

export default function ContactPage() {
  return (
    <main className="min-h-screen bg-slate-950 text-white font-sans selection:bg-green-500 selection:text-black flex flex-col justify-center">
      
      {/* --- BACKGROUND GLOW EFFECTS --- */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[120px]" />
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-green-600/10 rounded-full blur-[120px]" />
      </div>

      <div className="relative z-10 max-w-4xl mx-auto px-6 w-full">
        
        {/* --- HEADER --- */}
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="text-center mb-16"
        >
          <h1 className="text-5xl md:text-7xl font-black mb-4 tracking-tight leading-tight">
            Contact <span className="text-transparent bg-clip-text bg-gradient-to-r from-green-400 to-blue-500">CGINFRAX</span>
          </h1>
          <p className="text-gray-400 text-lg md:text-xl">
            Direct connection. No waiting.
          </p>
        </motion.div>

        {/* --- DIRECT ACTION GRID --- */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          {/* 1. WHATSAPP CARD (MAIN FOCUS) */}
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.2 }}
            onClick={() => window.open('https://wa.me/919131460470', '_blank')}
            className="group col-span-1 md:col-span-2 bg-[#25D366] hover:bg-[#20bd5a] cursor-pointer rounded-[2.5rem] p-8 md:p-10 relative overflow-hidden transition-all duration-300 hover:shadow-[0_0_40px_rgba(37,211,102,0.4)]"
          >
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-black/10 rounded-2xl flex items-center justify-center backdrop-blur-sm">
                  <MessageCircle size={36} className="text-white" />
                </div>
                <div className="text-center md:text-left">
                  <h3 className="text-2xl md:text-3xl font-black text-white">Chat on WhatsApp</h3>
                  <p className="text-white/80 font-medium text-lg">+91 91314 60470</p>
                </div>
              </div>
              <div className="bg-white text-[#25D366] px-8 py-3 rounded-full font-bold text-lg flex items-center gap-2 group-hover:scale-105 transition-transform shadow-lg">
                Start Chat <ArrowUpRight size={24} />
              </div>
            </div>
          </motion.div>

          {/* 2. CALL CARD */}
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            onClick={() => window.open('tel:919131460470')}
            className="group bg-white/5 border border-white/10 backdrop-blur-xl rounded-[2.5rem] p-8 cursor-pointer hover:bg-white/10 transition-all hover:border-blue-500/50"
          >
            <div className="flex justify-between items-start mb-8">
              <div className="p-4 bg-blue-500/20 rounded-2xl text-blue-400 group-hover:text-white group-hover:bg-blue-500 transition-colors">
                <Phone size={28} />
              </div>
              <ArrowUpRight className="text-gray-500 group-hover:text-white transition-colors" />
            </div>
            <h3 className="text-xl font-bold mb-1">Call Directly</h3>
            <p className="text-xl font-mono font-bold text-blue-400">+91 91314 60470</p>
          </motion.div>

          {/* 3. EMAIL CARD */}
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 }}
            onClick={() => window.open('mailto:support@cginfrax.com')}
            className="group bg-white/5 border border-white/10 backdrop-blur-xl rounded-[2.5rem] p-8 cursor-pointer hover:bg-white/10 transition-all hover:border-purple-500/50"
          >
            <div className="flex justify-between items-start mb-8">
              <div className="p-4 bg-purple-500/20 rounded-2xl text-purple-400 group-hover:text-white group-hover:bg-purple-500 transition-colors">
                <Mail size={28} />
              </div>
              <ArrowUpRight className="text-gray-500 group-hover:text-white transition-colors" />
            </div>
            <h3 className="text-xl font-bold mb-1">Email Support</h3>
            <p className="text-xl font-bold text-purple-400">support@cginfrax.com</p>
          </motion.div>

        </div>

      </div>
    </main>
  );
}